import{_ as a,a as d,b as e,c as i}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as o,o as l,c as r,a2 as n}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"WebDAV 渠道添加说明","description":"","frontmatter":{},"headers":[],"relativePath":"cn/upload/webdav.md","filePath":"cn/upload/webdav.md","lastUpdated":1781962217000}'),s={name:"cn/upload/webdav.md"};function c(h,t,p,b,u,m){return l(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="webdav-渠道添加说明" tabindex="-1">WebDAV 渠道添加说明 <a class="header-anchor" href="#webdav-渠道添加说明" aria-label="Permalink to &quot;WebDAV 渠道添加说明&quot;">​</a></h1><h2 id="适合什么场景" tabindex="-1">适合什么场景 <a class="header-anchor" href="#适合什么场景" aria-label="Permalink to &quot;适合什么场景&quot;">​</a></h2><ul><li>你有 NAS、网盘或对象存储服务提供的 WebDAV 地址。</li><li>你希望把图片上传到自己的 WebDAV 目录里。</li><li>你希望配置和凭据保存在 D1 上传渠道表 <code>upload_channels</code> 中，不直接放在前端页面里长期暴露。</li></ul><h2 id="添加前要准备什么" tabindex="-1">添加前要准备什么 <a class="header-anchor" href="#添加前要准备什么" aria-label="Permalink to &quot;添加前要准备什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需要准备</th><th>用途</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>服务端 WebDAV 地址，例如 <code>https://nas.example.com/dav</code></td></tr><tr><td>用户名</td><td>登录 WebDAV 服务使用</td></tr><tr><td>密码</td><td>登录 WebDAV 服务使用</td></tr><tr><td>鉴权模式</td><td>默认 <code>Basic</code>，也可以按服务端要求选择 <code>Digest</code> 或自动协商</td></tr><tr><td>存储目录</td><td>文件保存目录，默认 <code>imgbed</code></td></tr></tbody></table><h2 id="入口位置" tabindex="-1">入口位置 <a class="header-anchor" href="#入口位置" aria-label="Permalink to &quot;入口位置&quot;">​</a></h2><ol><li>进入系统配置。</li><li>打开上传设置。</li><li>点击右上角“添加渠道”。</li><li>选择 <code>WebDAV</code>。</li></ol><h2 id="字段说明" tabindex="-1">字段说明 <a class="header-anchor" href="#字段说明" aria-label="Permalink to &quot;字段说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>作用</th><th>是否必填</th></tr></thead><tbody><tr><td>渠道名称</td><td>用来区分当前 WebDAV 渠道，例如 <code>koofr</code>、<code>nas</code></td><td>是</td></tr><tr><td>Endpoint</td><td>WebDAV 服务地址，需要填写完整 <code>https://</code> 地址</td><td>是</td></tr><tr><td>用户名</td><td>WebDAV 登录用户名</td><td>是</td></tr><tr><td>密码</td><td>WebDAV 登录密码</td><td>是</td></tr><tr><td>鉴权模式</td><td>一般选 <code>Basic</code>；服务端要求摘要认证时选 <code>Digest</code></td><td>是</td></tr><tr><td>存储目录</td><td>文件保存目录，默认 <code>imgbed</code></td><td>否</td></tr></tbody></table><h2 id="以-fie-nl-tab-digital-为例" tabindex="-1">以 fie.nl.tab.digital 为例 <a class="header-anchor" href="#以-fie-nl-tab-digital-为例" aria-label="Permalink to &quot;以 fie.nl.tab.digital 为例&quot;">​</a></h2><h3 id="_1-创建应用密码" tabindex="-1">1. 创建应用密码 <a class="header-anchor" href="#_1-创建应用密码" aria-label="Permalink to &quot;1. 创建应用密码&quot;">​</a></h3><p>进入账号安全设置，找到应用程序密码，创建一个新的应用密码。</p><p><img src="'+a+'" alt="创建应用密码" loading="lazy"></p><p>创建完成后，复制并保存这串新应用程序密码。这个密码通常只显示一次，关闭页面后就看不到了。</p><p><img src="'+d+'" alt="记住新应用程序密码" loading="lazy"></p><h3 id="_2-回图床填写-webdav-配置" tabindex="-1">2. 回图床填写 WebDAV 配置 <a class="header-anchor" href="#_2-回图床填写-webdav-配置" aria-label="Permalink to &quot;2. 回图床填写 WebDAV 配置&quot;">​</a></h3><p>回到图床后台添加 WebDAV 渠道，按下面方式填写：</p><table tabindex="0"><thead><tr><th>页面字段</th><th>填写内容</th></tr></thead><tbody><tr><td>Endpoint</td><td><code>https://fie.nl.tab.digital/</code> 提供的 WebDAV 地址</td></tr><tr><td>用户名</td><td>你的 WebDAV 用户名</td></tr><tr><td>密码</td><td>刚才创建的新应用程序密码</td></tr><tr><td>鉴权模式</td><td>一般先选 <code>Basic</code></td></tr><tr><td>存储目录</td><td>默认 <code>imgbed</code>，也可以改成自己的目录</td></tr></tbody></table><p><img src="'+e+'" alt="填写配置" loading="lazy"></p><h2 id="大文件上传能力" tabindex="-1">大文件上传能力 <a class="header-anchor" href="#大文件上传能力" aria-label="Permalink to &quot;大文件上传能力&quot;">​</a></h2><p>WebDAV 渠道现在走真会话分块。</p><p>小文件会直接上传为一个完整文件；超过 64 MiB 的文件会自动切成 10 MiB 左右的分块，分别上传到远端分块目录。</p><p>这里不要求 WebDAV 服务支持 <code>partial update</code>（部分更新）或按偏移写入。系统不会在远端把分块重新合成一个文件，而是保存分块清单，读取文件时再按清单顺序读取分块并拼接返回。</p><p>简单理解：</p><table tabindex="0"><thead><tr><th>文件大小</th><th>上传方式</th><th>远端保存形态</th></tr></thead><tbody><tr><td>小于等于 64 MiB</td><td>普通上传</td><td>一个完整文件</td></tr><tr><td>大于 64 MiB</td><td>真会话分块上传</td><td>一个分块目录，里面保存多个分块文件</td></tr></tbody></table><p>分块目录只影响远端存储结构，不会改变图床里的文件链接。用户访问时仍然使用原来的 <code>/file/...</code> 地址。</p><h2 id="添加步骤" tabindex="-1">添加步骤 <a class="header-anchor" href="#添加步骤" aria-label="Permalink to &quot;添加步骤&quot;">​</a></h2><ol><li>打开上传设置页面。</li><li>点击“添加渠道”。</li><li>选择 <code>WebDAV</code>。</li><li>渠道名称填一个自己能看懂的名字，例如 <code>koofr</code>。</li><li><code>Endpoint</code> 填 WebDAV 地址，例如 <code>https://app.koofr.net/dav/Koofr</code>。</li><li>填写用户名和密码。</li><li>鉴权模式默认选 <code>Basic</code>。</li><li>存储目录默认 <code>imgbed</code>，也可以改成自己的目录。</li><li>点击保存。</li><li>保存后查看渠道卡片，再查询容量或上传测试文件确认连接可用。</li></ol><h2 id="添加完成后怎么检查" tabindex="-1">添加完成后怎么检查 <a class="header-anchor" href="#添加完成后怎么检查" aria-label="Permalink to &quot;添加完成后怎么检查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>检查项</th><th>检查方式</th></tr></thead><tbody><tr><td>渠道卡片是否出现</td><td>保存后，上传设置页面应显示 WebDAV 渠道卡片</td></tr><tr><td>渠道是否启用</td><td>卡片右上角开关应保持开启</td></tr><tr><td>凭据是否保存</td><td>详情页能看到 Endpoint、用户名、鉴权模式、存储目录</td></tr><tr><td>小文件上传是否正常</td><td>上传一张测试图片，确认 WebDAV 目录里出现文件</td></tr><tr><td>大文件上传规则</td><td>超过 64 MiB 会走分块上传，远端会保存分块目录和分块文件</td></tr><tr><td>容量查询是否可用</td><td>点击查询，如果服务端支持容量信息，会显示已用容量和总容量</td></tr></tbody></table><p><img src="'+i+`" alt="查询额度成功" loading="lazy"></p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="webdav-大文件为什么会出现分块目录" tabindex="-1">WebDAV 大文件为什么会出现分块目录？ <a class="header-anchor" href="#webdav-大文件为什么会出现分块目录" aria-label="Permalink to &quot;WebDAV 大文件为什么会出现分块目录？&quot;">​</a></h3><p>这是现在的大文件保存方式。</p><p>超过 64 MiB 的文件不会在远端合成一个大文件，而是保存为分块目录。图床会记录分块清单，访问时按顺序读取分块并返回完整内容。</p><h3 id="大文件上传失败先检查什么" tabindex="-1">大文件上传失败先检查什么？ <a class="header-anchor" href="#大文件上传失败先检查什么" aria-label="Permalink to &quot;大文件上传失败先检查什么？&quot;">​</a></h3><p>先检查 Endpoint、用户名、密码和存储目录是否正确，再检查 WebDAV 服务是否允许创建目录、写入文件、读取文件。</p><p>如果容量查询失败，但小文件上传正常，通常是服务端不支持或限制容量信息查询，不一定代表上传不可用。</p><h3 id="鉴权模式怎么选" tabindex="-1">鉴权模式怎么选？ <a class="header-anchor" href="#鉴权模式怎么选" aria-label="Permalink to &quot;鉴权模式怎么选？&quot;">​</a></h3><p>一般先用 <code>Basic</code>。</p><p>如果服务端明确要求摘要认证，就选 <code>Digest</code>。</p><p>不确定时可以选自动协商。</p><h2 id="一句话流程速查" tabindex="-1">一句话流程速查 <a class="header-anchor" href="#一句话流程速查" aria-label="Permalink to &quot;一句话流程速查&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>准备 WebDAV 地址、用户名、密码</span></span>
<span class="line"><span>-&gt; 打开上传设置</span></span>
<span class="line"><span>-&gt; 添加渠道</span></span>
<span class="line"><span>-&gt; 选择 WebDAV</span></span>
<span class="line"><span>-&gt; 填写 Endpoint / 用户名 / 密码</span></span>
<span class="line"><span>-&gt; 鉴权模式默认 Basic</span></span>
<span class="line"><span>-&gt; 存储目录默认 imgbed</span></span>
<span class="line"><span>-&gt; 保存</span></span>
<span class="line"><span>-&gt; 查询容量</span></span>
<span class="line"><span>-&gt; 上传测试文件</span></span></code></pre></div>`,44)])])}const _=o(s,[["render",c]]);export{f as __pageData,_ as default};
